+    pub fn argsort(&self) -> Vec<usize> {
+        let mut indexed: Vec<(usize, &Scalar)> = self.values.iter().enumerate().collect();
+        indexed.sort_by(|a, b| compare_scalars_na_last(a.1, b.1, true));
+        indexed.into_iter().map(|(i, _)| i).collect()
